#include<stdio.h>

int main()
{
    int x, y;
    scanf ("%d %d", &x, &y);
    if (x == y) {
        printf ("No\n");
        return 0;
    }
    else if (x < y) {
        if (y - x == 1) {
            printf ("Yes\n");
            return 0;
        }
        else {
            printf ("No\n");
            return 0;
        }
    }
    else {
        if (y == 0 || y == 1) {
            printf ("No\n");
            return 0;
        }
        y = y - 1;
        x = x - y;
        if (x & 1) {
            printf ("No\n");
            return 0;
        }
        else {
            printf ("Yes\n");
            return 0;
        }
    }
    return 0;
}

