fn main() {
    let mut stdin = String::new();
    std::io::Read::read_to_string(
        &mut std::io::stdin(),
        &mut stdin).unwrap();
    let mut stdin = stdin.split_whitespace();
    let mut get = || stdin.next().unwrap();
    macro_rules! get {
        () => (get().parse::<i64>().unwrap());
        ($t:ty) => (get().parse::<$t>().unwrap());
    }

    let x = get!();
    let y = get!();

    if y == 0 || (y == 1 && x > 0) || x < y - 1 {
        println!("No");
        return;
    }

    let d = x - (y - 1);

    if d % 2 != 0 {
        println!("No");
        return;
    }

    println!("Yes");

}
